74	\section{Braided (symmetric) structure}
75	
76	The symmetric structure on $X.\mathrm{Modules}$ is what enables the commutative-monoid structure on the skeleton of objects, hence the commutative-group structure on $\mathrm{LineBundle}\,X = (\mathrm{Skeleton}\,X.\mathrm{Modules})^\times$ (Chapter~\ref{chap:Picard_LineBundle}). It is recorded in two no-content registration steps, exposing transitively-existing structure rather than building anything new.
77	
78	\begin{theorem}\leanok
79	[Symmetric structure on the presheaf side]
80	  \label{thm:Modules_BraidedCategoryPresheaf}
81	  \lean{AlgebraicGeometry.Scheme.Modules.instBraidedCategoryPresheaf}
82	  For every scheme $X$, the category $\mathrm{PresheafOfModules}\,\mathcal O_X$ of presheaves of $\mathcal O_X$-modules carries a canonical \emph{symmetric} (in particular braided) monoidal structure with tensor product computed pointwise.
83	\end{theorem}
84	
85	\begin{proof}\leanok
86	  Pointwise on each open $U \subseteq X$, the tensor product is the standard tensor on $\mathrm{ModuleCat}\,\mathcal O_X(U)$, which is symmetric monoidal (\texttt{Mathlib.Algebra.Category.ModuleCat.Monoidal}). The presheaf-level instance lifts this pointwise (\texttt{Mathlib.Algebra.Category.ModuleCat.Presheaf.Monoidal}), and the project simply transports the symmetric structure across the definitional equality $X.\mathrm{ringCatSheaf}.\mathrm{obj} = X.\mathrm{sheaf}.\mathrm{obj} \circ \mathrm{forget}_2\,\mathrm{CommRingCat}\,\mathrm{RingCat}$, mirroring the analogous monoidal-side bridging instance (Theorem~\ref{thm:Modules_MonoidalCategory}).
87	\end{proof}
88	
89	\begin{theorem}\leanok
90	[Symmetric structure on the sheaf side]
91	  \label{thm:Modules_BraidedCategory}
92	  \lean{AlgebraicGeometry.Scheme.Modules.instBraidedCategory}
93	  \uses{thm:Modules_MonoidalCategory, thm:Modules_BraidedCategoryPresheaf}
94	  For every scheme $X$, the symmetric monoidal category $X.\mathrm{Modules}$ carries a canonical braided (in fact symmetric) structure with braiding given by the standard tensor-swap, transported from the presheaf side through sheafification.
95	\end{theorem}
96	
97	\begin{proof}\leanok
98	  \uses{thm:Modules_MonoidalCategory, thm:Modules_BraidedCategoryPresheaf}
99	  The \texttt{LocalizedMonoidal} machinery (\texttt{CategoryTheory.Localization.Monoidal.Braided}) provides a braided structure on the localisation $L(\mathrm{PresheafOfModules}\,\mathcal O_X)/W$ whenever the source category is braided and the localising class $W$ is monoidal. Both inputs are in place: the presheaf side is symmetric (Theorem~\ref{thm:Modules_BraidedCategoryPresheaf}), and $W$ is monoidal (the named-deferred gap $\mathtt{instIsMonoidal\_W}$ of Remark~\ref{rem:W_IsMonoidal_load_bearing}). The sheaf-side braiding is then the image under $L$ of the presheaf-side braiding, and its hexagon axioms transfer through the universal property of the monoidal localisation.
100	\end{proof}
101	
102	\begin{remark}[No new mathematical content]
103	  Both instances above are project-side \emph{registrations} exposing structure that is transitively present in Mathlib. They become important only at C1 (Chapter~\ref{chap:Picard_LineBundle}), where the typeclass chain $\mathrm{BraidedCategory}\,X.\mathrm{Modules} \Rightarrow \mathrm{CommMonoid}\,(\mathrm{Skeleton}\,X.\mathrm{Modules}) \Rightarrow \mathrm{CommGroup}\,(\mathrm{Skeleton}\,X.\mathrm{Modules})^\times$ is invoked to give $\mathrm{LineBundle}\,X$ its commutative-group structure.
104	\end{remark}
